```go
package main

import (
	"io"
	"log"
	"net/http"
)

func main() {
	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		// Read the request body
		body, err := io.ReadAll(r.Body)
		if err != nil {
			log.Println("Error reading request body:", err)
			return
		}
		r.Body.Close() // Close the body to avoid resource leak

		// Print the request body
		log.Println("Request Content:", string(body))
	})

	// Start a server on localhost:8080
	log.Println("Server is running on :8080")
	http.ListenAndServe(":8080", nil)
}
```

This code sets up a simple HTTP server that reads and logs the content of incoming requests. Make sure to handle the request body properly by closing it after reading to avoid resource leaks.

