```cpp
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    int pipefd[2];
    if (pipe(pipefd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    int pid = fork();
    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    } else if (pid == 0) { // Child process
        // Close unnecessary file descriptors
        close(pipefd[1]);
        dup2(pipefd[0], STDIN_FILENO);
        dup2(pipefd[0], STDOUT_FILENO);
        close(pipefd[0]);

        // Execute your command here
        execlp("command", "command", NULL);
        std::cerr << "Exec failed" << std::endl;
        return 1;
    } else { // Parent process
        close(pipefd[0]);
        // Do something with pipefd[1]
        std::cout << "Parent process waits for child to finish..." << std::endl;
        wait(NULL);
        std::cout << "Child process finished." << std::endl;
    }

    return 0;
}
```

This code snippet demonstrates how to create a new process and connect its standard input and output to one file descriptor using a pipe. The child process replaces the current process with a specified command, while the parent process waits for the child to finish.
